INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9974bf44-ff46-4392-bd8f-98b3ee10f69b', $q$Cookieless, Privacy-First Tracking$q$, $q$Anonymizes visitor data and avoids cookies entirely, so websites using Fathom do not need to show a cookie consent banner while remaining compliant with GDPR, CCPA, and PECR.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9974bf44-ff46-4392-bd8f-98b3ee10f69b', $q$Real-Time Dashboard$q$, $q$Traffic, referrer, and campaign data appear in the dashboard close to real time, powered by a serverless ingestion pipeline built on AWS Lambda, SQS, and the SingleStore database.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9974bf44-ff46-4392-bd8f-98b3ee10f69b', $q$Event and E-commerce Tracking$q$, $q$Tracks custom user interactions such as button clicks, signups, and purchases, along with e-commerce conversion data, included at no extra cost on every plan.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9974bf44-ff46-4392-bd8f-98b3ee10f69b', $q$UTM Campaign Tracking$q$, $q$Automatically captures UTM parameters so marketers can see which campaigns, channels, and sources are driving traffic and conversions.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9974bf44-ff46-4392-bd8f-98b3ee10f69b', $q$Forever Data Retention$q$, $q$Historical analytics data is retained in full for as long as the account remains active, rather than being sampled or purged after a fixed retention window.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9974bf44-ff46-4392-bd8f-98b3ee10f69b', $q$Automatic Bot Filtering$q$, $q$Filters out bots, scrapers, and spam traffic automatically so reported metrics reflect genuine human visitors.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9974bf44-ff46-4392-bd8f-98b3ee10f69b', $q$Full API Access$q$, $q$Provides developer API access (with an included request allowance) for pulling analytics data into custom dashboards, reports, or internal tools.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9974bf44-ff46-4392-bd8f-98b3ee10f69b', $q$Shared and Saved Dashboards$q$, $q$Lets teams save filtered dashboard views and share read-only, optionally password-protected dashboards with clients or stakeholders without giving them account access.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9974bf44-ff46-4392-bd8f-98b3ee10f69b', $q$No cookie consent banner required, with GDPR, CCPA, and PECR compliance built into the tracking approach$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9974bf44-ff46-4392-bd8f-98b3ee10f69b', $q$Lightweight tracking script (about 2kB) with minimal impact on page load speed$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9974bf44-ff46-4392-bd8f-98b3ee10f69b', $q$Simple, uncluttered dashboard that most users can understand without training, unlike Google Analytics$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9974bf44-ff46-4392-bd8f-98b3ee10f69b', $q$Flat, transparent pageview-based pricing with the same full feature set on every paid tier, and low marginal cost for agencies managing many client sites$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9974bf44-ff46-4392-bd8f-98b3ee10f69b', $q$No permanently free tier for the hosted product beyond a 7-day trial; the free Fathom Lite option requires self-hosting and technical setup$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9974bf44-ff46-4392-bd8f-98b3ee10f69b', $q$Narrower built-in analytics depth (such as advanced funnels and segmentation) than some competitors like Plausible$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9974bf44-ff46-4392-bd8f-98b3ee10f69b', $q$Costs can rise quickly for high-traffic sites since pricing scales directly with monthly pageviews$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9974bf44-ff46-4392-bd8f-98b3ee10f69b', $q$Small team size compared to major analytics vendors, which can mean a slower pace of new integrations and features$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9974bf44-ff46-4392-bd8f-98b3ee10f69b', $q$Is Fathom Analytics really cookieless?$q$, $q$Yes. Fathom does not set tracking cookies on visitor devices and does not collect personally identifiable information, which is central to its privacy-first positioning.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9974bf44-ff46-4392-bd8f-98b3ee10f69b', $q$Does using Fathom Analytics mean I can skip a cookie consent banner?$q$, $q$Fathom states that because its tracking is cookieless and anonymized, sites using only Fathom for analytics typically do not need to display a cookie consent banner under GDPR, CCPA, and PECR, though businesses should confirm this against their own overall compliance requirements.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9974bf44-ff46-4392-bd8f-98b3ee10f69b', $q$How much does Fathom Analytics cost?$q$, $q$Pricing is based on average monthly pageviews, starting around $15 per month for up to roughly 100,000 monthly pageviews, with published tiers scaling up to around 15 million pageviews and custom enterprise pricing above that.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9974bf44-ff46-4392-bd8f-98b3ee10f69b', $q$Is there a free version of Fathom Analytics?$q$, $q$The hosted Fathom Analytics product offers only a 7-day free trial, not a permanent free plan. However, Fathom also maintains Fathom Lite, a free, open-source, self-hosted analytics tool available on GitHub.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9974bf44-ff46-4392-bd8f-98b3ee10f69b', $q$Who founded Fathom Analytics?$q$, $q$Fathom Analytics was founded in 2018 by Paul Jarvis, who conceived the original privacy-focused dashboard concept, and Jack Ellis, who joined as technical co-founder in early 2019 and now runs the company; it remains bootstrapped with no outside venture investment.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9974bf44-ff46-4392-bd8f-98b3ee10f69b', $q$How does Fathom Analytics compare to Google Analytics?$q$, $q$Fathom offers a simpler dashboard, does not require cookies or a consent banner, and uses a much lighter tracking script, but it provides a narrower analytics feature set than Google Analytics and is a paid subscription product rather than free.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9974bf44-ff46-4392-bd8f-98b3ee10f69b', $q$Replacing Google Analytics with a privacy-compliant tool$q$, $q$Site owners who want traffic and campaign insights without collecting personal visitor data or displaying a cookie consent banner switch to Fathom for its cookieless, GDPR/CCPA-oriented tracking approach.$q$, $q$Privacy-conscious website owners, bloggers, and small businesses$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9974bf44-ff46-4392-bd8f-98b3ee10f69b', $q$Managing analytics across many client websites$q$, $q$Because pricing is based on total pageview volume rather than per-site fees within the included site allowance, agencies and freelance developers use Fathom to track multiple client sites under a single account at a predictable flat cost.$q$, $q$Web agencies and freelance developers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9974bf44-ff46-4392-bd8f-98b3ee10f69b', $q$Meeting legal and compliance requirements for analytics$q$, $q$Organizations with legal, procurement, or compliance teams that need analytics tooling with documented GDPR, CCPA, and PECR compliance and no personal-data collection adopt Fathom for its compliance-first reputation.$q$, $q$Compliance-sensitive businesses and larger organizations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9974bf44-ff46-4392-bd8f-98b3ee10f69b', $q$100K Pageviews$q$, $q$$15/month$q$, $q$monthly (discounted on annual billing)$q$, NULL, $q$["Up to approximately 100,000 monthly pageviews","50 sites included","Full feature set: events, e-commerce, UTM tracking","API access","7-day free trial"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9974bf44-ff46-4392-bd8f-98b3ee10f69b', $q$200K Pageviews$q$, $q$$24/month$q$, $q$monthly (discounted on annual billing)$q$, NULL, $q$["Up to approximately 200,000 monthly pageviews","Full feature set included","Bot and spam filtering","Unlimited email reports and exports"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9974bf44-ff46-4392-bd8f-98b3ee10f69b', $q$500K Pageviews$q$, $q$$45/month$q$, $q$monthly (discounted on annual billing)$q$, NULL, $q$["Up to approximately 500,000 monthly pageviews","50+ sites included","Saved and shared dashboards","Full API access"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9974bf44-ff46-4392-bd8f-98b3ee10f69b', $q$1M Pageviews$q$, $q$$54/month$q$, $q$monthly (discounted on annual billing)$q$, NULL, $q$["Up to approximately 1,000,000 monthly pageviews","Additional sites available in packs","Full feature set included"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9974bf44-ff46-4392-bd8f-98b3ee10f69b', $q$2M Pageviews$q$, $q$$74/month$q$, $q$monthly (discounted on annual billing)$q$, NULL, $q$["Up to approximately 2,000,000 monthly pageviews","Full feature set included","Priority-scale serverless infrastructure"]$q$::jsonb, 4);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9974bf44-ff46-4392-bd8f-98b3ee10f69b', $q$5M Pageviews$q$, $q$$94/month$q$, $q$monthly (discounted on annual billing)$q$, NULL, $q$["Up to approximately 5,000,000 monthly pageviews","Full feature set included"]$q$::jsonb, 5);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9974bf44-ff46-4392-bd8f-98b3ee10f69b', $q$10M Pageviews$q$, $q$$124/month$q$, $q$monthly (discounted on annual billing)$q$, NULL, $q$["Up to approximately 10,000,000 monthly pageviews","Full feature set included"]$q$::jsonb, 6);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9974bf44-ff46-4392-bd8f-98b3ee10f69b', $q$15M Pageviews$q$, $q$$184/month$q$, $q$monthly (discounted on annual billing)$q$, NULL, $q$["Up to approximately 15,000,000 monthly pageviews","Full feature set included"]$q$::jsonb, 7);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9974bf44-ff46-4392-bd8f-98b3ee10f69b', $q$Enterprise$q$, $q$Custom (contact sales)$q$, $q$custom$q$, NULL, $q$["For sites above roughly 15-25 million monthly pageviews","Custom contract terms","Full feature set included"]$q$::jsonb, 8);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9974bf44-ff46-4392-bd8f-98b3ee10f69b', $q$Fathom Lite (Open Source)$q$, $q$Free$q$, $q$self-hosted, no billing$q$, NULL, $q$["Self-hosted on your own infrastructure","Open-source codebase available on GitHub","No official support included","Cookieless, privacy-respecting tracking"]$q$::jsonb, 9);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9974bf44-ff46-4392-bd8f-98b3ee10f69b', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Fathom Analytics is a privacy-first, cookieless website analytics tool built to replace Google Analytics for site owners who want simple traffic insights without collecting personal visitor data. It tracks pageviews, referrers, UTM campaign performance, custom events, and e-commerce conversions through a lightweight script (around 2 kilobytes) that site owners add to their pages, with results shown in a real-time dashboard.$q$, $q$The company was founded in 2018 by writer and designer Paul Jarvis, who publicly shared a mockup of a simpler analytics dashboard concept, and developer Jack Ellis, who joined as technical co-founder in early 2019. Fathom is bootstrapped and privately owned, based in Victoria, British Columbia, Canada, with a small, fully remote team and no outside venture investment.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9974bf44-ff46-4392-bd8f-98b3ee10f69b', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$All Fathom Analytics plans include the same core capabilities regardless of pageview tier: event and e-commerce tracking, UTM campaign tracking, automatic bot and spam filtering, saved and password-protectable shared dashboards, full API access, and unlimited email reports and data exports. The company states it retains full historical analytics data for as long as an account is active, rather than sampling or purging older data.$q$, $q$Under the hood, Fathom runs on serverless cloud infrastructure: incoming traffic is processed through AWS Lambda and queued via Amazon SQS across multiple availability zones before being written into SingleStore, a distributed SQL database built for high-volume analytical workloads. This pipeline is designed to keep the dashboard near real-time even for high-traffic sites, and because tracking is cookieless and anonymized, sites using Fathom do not need to show a cookie consent banner under GDPR, CCPA, or PECR.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9974bf44-ff46-4392-bd8f-98b3ee10f69b', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Fathom Analytics is priced by expected average monthly pageviews rather than by feature tier, so every paying plan unlocks the full feature set. Plans start around $15 per month for up to roughly 100,000 monthly pageviews and scale upward through published tiers around 200,000, 500,000, 1 million, 2 million, 5 million, 10 million, and 15 million pageviews, with custom enterprise pricing available for higher volumes. A seven-day free trial precedes billing, annual billing includes roughly two months free compared to paying monthly, and additional sites beyond the base allowance can be added in packs for a flat monthly or yearly add-on fee.$q$, $q$Separately from the paid, cloud-hosted product, Fathom also maintains Fathom Lite, a free and open-source, self-hosted version of its original analytics concept, distributed on GitHub for developers who want a no-cost privacy-respecting analytics tool they run and maintain on their own servers without official support.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9974bf44-ff46-4392-bd8f-98b3ee10f69b', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9974bf44-ff46-4392-bd8f-98b3ee10f69b', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9974bf44-ff46-4392-bd8f-98b3ee10f69b', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9974bf44-ff46-4392-bd8f-98b3ee10f69b', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9974bf44-ff46-4392-bd8f-98b3ee10f69b', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3185965d-fd1d-45c7-a0e1-03ac82f24008', $q$Nested, customizable tags$q$, $q$Organize bookmarks with color-coded, hierarchical tags that can be pinned, letting a single link belong to multiple categories instead of a single rigid folder.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3185965d-fd1d-45c7-a0e1-03ac82f24008', $q$Automatic metadata fetching$q$, $q$When a link is saved, Faved automatically pulls the page title, description, and preview image so bookmarks are useful and searchable without manual entry.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3185965d-fd1d-45c7-a0e1-03ac82f24008', $q$Duplicate detection$q$, $q$The platform flags and helps prevent duplicate bookmarks so large collections stay clean and easy to browse over time.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3185965d-fd1d-45c7-a0e1-03ac82f24008', $q$Multiple capture methods$q$, $q$Save pages via the Chrome extension, a cross-browser bookmarklet that requires no install, or the native Share menu on iPhone, iPad, and Mac, with Apple Shortcuts support.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3185965d-fd1d-45c7-a0e1-03ac82f24008', $q$Instant search and bulk actions$q$, $q$Find any saved link quickly with flexible search and sorting, and manage many bookmarks at once with bulk tagging, moving, and deletion.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3185965d-fd1d-45c7-a0e1-03ac82f24008', $q$Self-hosting via Docker$q$, $q$Deploy the fully open-source codebase on your own infrastructure with a single Docker command and no external dependencies, keeping all data local.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3185965d-fd1d-45c7-a0e1-03ac82f24008', $q$Import and migration tools$q$, $q$Bring in existing bookmarks from Chrome, Safari, Firefox, and Edge with folder structure preserved, or migrate directly from Raindrop.io and Pocket with tags and collections intact.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3185965d-fd1d-45c7-a0e1-03ac82f24008', $q$Responsive PWA with dark mode$q$, $q$A fully responsive interface installable as a Progressive Web App across mobile, tablet, and desktop, with light and dark mode that follows system preferences.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3185965d-fd1d-45c7-a0e1-03ac82f24008', $q$Fully open-source under the MIT license, so the code can be inspected, audited, and self-hosted for free with no vendor lock-in.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3185965d-fd1d-45c7-a0e1-03ac82f24008', $q$Nested, color-customizable tagging is more flexible than flat folder structures used by many older bookmark managers.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3185965d-fd1d-45c7-a0e1-03ac82f24008', $q$Fast, lightweight architecture (PHP, SQLite, Docker) that the maker states loads large libraries in well under 100 milliseconds.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3185965d-fd1d-45c7-a0e1-03ac82f24008', $q$Low-cost Cloud tier ($2.50/month billed annually) with a 14-day free trial makes the managed option accessible for individuals.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3185965d-fd1d-45c7-a0e1-03ac82f24008', $q$As a project launched in 2025, it lacks the long track record, enterprise references, and third-party audits of more established tools like Raindrop.io.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3185965d-fd1d-45c7-a0e1-03ac82f24008', $q$Self-hosting requires comfort with Docker and basic server administration, which is a barrier for non-technical users.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3185965d-fd1d-45c7-a0e1-03ac82f24008', $q$The free Cloud trial is time-limited (14 days), after which continued use of the managed service requires a paid subscription.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3185965d-fd1d-45c7-a0e1-03ac82f24008', $q$Cloud Team pricing is custom and not published, so organizations must contact the maker to get an exact quote.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3185965d-fd1d-45c7-a0e1-03ac82f24008', $q$What is Faved?$q$, $q$Faved is an open-source bookmark manager that lets users save, tag, and organize web links using a customizable nested-tag system, available either as a free self-hosted app or as a paid managed cloud service.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3185965d-fd1d-45c7-a0e1-03ac82f24008', $q$Is Faved free to use?$q$, $q$Yes. The self-hosted version is completely free and open source under the MIT license with unlimited bookmarks. Faved Cloud, the managed hosting option, starts at $2.50 per month when billed annually and includes a 14-day free trial.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3185965d-fd1d-45c7-a0e1-03ac82f24008', $q$Can I self-host Faved?$q$, $q$Yes. Faved can be deployed on your own server with a single Docker command and no external dependencies, and the full source code is available on GitHub under an MIT license.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3185965d-fd1d-45c7-a0e1-03ac82f24008', $q$How much does Faved Cloud cost?$q$, $q$Faved Cloud is priced at $2.50 per month when billed annually (about $30 per year) and supports up to 50,000 bookmarks. A custom-priced Cloud Team plan is also available for organizations that need unlimited bookmarks, SSO, and multi-user access.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3185965d-fd1d-45c7-a0e1-03ac82f24008', $q$Can I import my existing bookmarks into Faved?$q$, $q$Yes. Faved supports importing bookmarks from Chrome, Safari, Firefox, and Edge with folder structures preserved as nested tags, and offers dedicated migration tools for moving data from Raindrop.io and Pocket.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3185965d-fd1d-45c7-a0e1-03ac82f24008', $q$Who built Faved and when did it launch?$q$, $q$Faved was created by developer Denis Dvali, who previously worked at Automattic and also founded Uptimely.cloud. The project's code was published on GitHub in June 2025 and the product launched publicly shortly after.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3185965d-fd1d-45c7-a0e1-03ac82f24008', $q$Privacy-conscious self-hosting$q$, $q$Individuals and developers who want full control over their bookmark data can deploy the open-source version on their own server via Docker, keeping every link and tag on infrastructure they own.$q$, $q$Privacy-focused developers and self-hosting enthusiasts$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3185965d-fd1d-45c7-a0e1-03ac82f24008', $q$Managing large research or reading libraries$q$, $q$Researchers, writers, and heavy internet users who accumulate thousands of links use Faved's nested tags, automatic metadata capture, and instant search to keep large collections organized and quickly retrievable.$q$, $q$Researchers, students, and knowledge workers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3185965d-fd1d-45c7-a0e1-03ac82f24008', $q$Shared team link libraries$q$, $q$Small teams and organizations use the Cloud Team plan to maintain a single, collaboratively managed bookmark library with SSO, user management, and custom branding for shared resources and internal knowledge collections.$q$, $q$Small teams and organizations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3185965d-fd1d-45c7-a0e1-03ac82f24008', $q$Self-Hosted$q$, $q$Free$q$, $q$N/A (open source)$q$, NULL, $q$["Unlimited bookmarks","Full data ownership on your own infrastructure","MIT-licensed open-source code","Deploy via Docker with no external dependencies","Nested tags, search, duplicate detection, and bulk actions"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3185965d-fd1d-45c7-a0e1-03ac82f24008', $q$Cloud$q$, $q$$2.50/month (billed annually at $30/year)$q$, $q$annual$q$, NULL, $q$["Up to 50,000 bookmarks","14-day free trial","Encryption and automatic backups","Automatic software updates","Early access to new features","Email support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3185965d-fd1d-45c7-a0e1-03ac82f24008', $q$Cloud Team$q$, $q$Custom pricing$q$, $q$custom$q$, NULL, $q$["Unlimited bookmarks","Multi-user access and user management","Single sign-on (SSO)","Custom branding","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3185965d-fd1d-45c7-a0e1-03ac82f24008', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Faved is an open-source bookmark manager designed for people who have outgrown simple browser bookmarks and flat folder structures. Instead of nesting links inside folders, Faved organizes everything with customizable, color-coded nested tags, which lets a single saved link belong to multiple overlapping categories at once and stay easy to find as a collection grows into the thousands.$q$, $q$The product is available in two forms: a free, self-hosted version that anyone can deploy on their own server using Docker, and a managed Faved Cloud service for people who would rather not run their own infrastructure. Both versions share the same MIT-licensed open-source codebase, and the company describes data ownership and privacy as central to the product's philosophy rather than an afterthought.$q$, $q$Faved was created by developer Denis Dvali, who previously worked at Automattic and who also runs the uptime-monitoring service Uptimely.cloud. The project's codebase went public on GitHub in mid-2025 and launched publicly shortly after, making it a relatively young entrant in the bookmark-management space compared to longer-established tools like Raindrop.io or Pocket.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3185965d-fd1d-45c7-a0e1-03ac82f24008', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The core of Faved's organization system is nested, customizable tagging: tags can be color-coded, pinned for quick access, and applied in combination so users avoid the rigidity of a single folder tree. When a link is saved, Faved automatically fetches the page's title, description, and preview image, and it runs duplicate detection so the same URL is not saved twice by accident.$q$, $q$Capture options include a Chrome browser extension, a universal bookmarklet that works in any browser without an install, and native Share menu integration on iPhone, iPad, and Mac, with Apple Shortcuts support for further automation. The interface itself is fully responsive, installable as a Progressive Web App, supports light and dark mode tied to system settings, and offers instant search plus bulk actions for managing large numbers of bookmarks at once.$q$, $q$For people migrating from another tool, Faved imports bookmarks from Chrome, Safari, Firefox, and Edge while converting existing folder structures into nested tags, and it provides dedicated migration paths from Raindrop.io and Pocket that preserve tags and collections.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3185965d-fd1d-45c7-a0e1-03ac82f24008', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Faved offers three pricing tiers. The Self-Hosted tier is completely free and open source under the MIT license, with unlimited bookmarks and full data control, but it requires the user to deploy and maintain their own Docker instance.$q$, $q$The Faved Cloud tier is a managed, hosted version priced at $2.50 per month when billed annually ($30 per year), with a 14-day free trial. It supports up to 50,000 bookmarks and adds encryption, automatic backups, automatic updates, early access to new features, and email support.$q$, $q$The Cloud Team tier is aimed at organizations and is priced on a custom, contact-for-pricing basis. It removes the bookmark limit entirely and adds multi-user access, single sign-on (SSO), user management, custom branding, and priority support for teams that want a shared, collaboratively managed link library.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3185965d-fd1d-45c7-a0e1-03ac82f24008', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
