INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3185965d-fd1d-45c7-a0e1-03ac82f24008', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3185965d-fd1d-45c7-a0e1-03ac82f24008', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f7aac8e5-93a6-4551-b76b-53dae46d786f', $q$Offline and online store architecture$q$, $q$Feast pairs a batch-oriented offline store (BigQuery, Snowflake, Redshift, Postgres, Spark, DuckDB, and more) for historical training data with a low-latency online store (Redis, DynamoDB, Bigtable, Cassandra, and more) for real-time inference.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f7aac8e5-93a6-4551-b76b-53dae46d786f', $q$Point-in-time correct feature retrieval$q$, $q$Training datasets are assembled with time-aware joins that match each label to the feature values that were actually available at that moment, preventing future data from leaking into model training.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f7aac8e5-93a6-4551-b76b-53dae46d786f', $q$Central feature registry$q$, $q$A metadata registry catalogs entities, data sources, and feature views so teams can discover and reuse existing features instead of recomputing the same logic across projects.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f7aac8e5-93a6-4551-b76b-53dae46d786f', $q$Python SDK and CLI$q$, $q$Engineers define entities, feature views, and data sources as code using the Feast Python SDK and CLI, then apply and materialize those definitions into the registry and online store.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f7aac8e5-93a6-4551-b76b-53dae46d786f', $q$Feature server for non-Python apps$q$, $q$An optional feature server exposes feature reads and writes over an API so services written in Java, Go, or other languages can consume Feast without embedding the Python SDK.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f7aac8e5-93a6-4551-b76b-53dae46d786f', $q$Batch and streaming ingestion$q$, $q$Features can be materialized from batch sources on a schedule or pushed into the online store from streaming pipelines, supporting both periodic and near-real-time freshness needs.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f7aac8e5-93a6-4551-b76b-53dae46d786f', $q$Vector search for RAG and LLM apps$q$, $q$Integrations with vector-capable stores such as Qdrant, Milvus, and Faiss let teams store and retrieve embeddings alongside conventional features, extending Feast into retrieval-augmented generation use cases.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f7aac8e5-93a6-4551-b76b-53dae46d786f', $q$Data quality monitoring and observability$q$, $q$Baseline metrics, audit logging, and REST APIs let teams inspect what features were actually served, helping catch data quality regressions before they affect model performance.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f7aac8e5-93a6-4551-b76b-53dae46d786f', $q$Completely free and open source under the permissive Apache 2.0 license, with no vendor lock-in.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f7aac8e5-93a6-4551-b76b-53dae46d786f', $q$Broad ecosystem of pluggable offline and online store integrations, so teams can adopt it on infrastructure they already run.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f7aac8e5-93a6-4551-b76b-53dae46d786f', $q$Neutral, community-driven governance under the Linux Foundation rather than control by a single commercial vendor.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f7aac8e5-93a6-4551-b76b-53dae46d786f', $q$Point-in-time correct joins solve a genuinely hard and common bug (training-serving data leakage) that many teams otherwise handle manually.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f7aac8e5-93a6-4551-b76b-53dae46d786f', $q$No managed hosting from the project itself, so teams must operate their own offline and online store infrastructure and the engineering time that comes with it.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f7aac8e5-93a6-4551-b76b-53dae46d786f', $q$Requires meaningful data engineering and DevOps expertise to set up and operate compared to fully managed commercial alternatives.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f7aac8e5-93a6-4551-b76b-53dae46d786f', $q$Built-in streaming freshness, monitoring, and alerting capabilities are less mature than purpose-built commercial platforms like Tecton.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f7aac8e5-93a6-4551-b76b-53dae46d786f', $q$Concepts like feature views, entities, and point-in-time joins carry a learning curve for teams new to feature store design patterns.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f7aac8e5-93a6-4551-b76b-53dae46d786f', $q$Is Feast free to use?$q$, $q$Yes. Feast is fully open source under the Apache License 2.0, so there is no license fee. Costs come only from the infrastructure (databases, warehouses, compute) a team chooses to run it on.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f7aac8e5-93a6-4551-b76b-53dae46d786f', $q$Who created Feast?$q$, $q$Feast was created in 2018 as a joint project between Gojek and Google Cloud, and was publicly announced as open source in January 2019. It moved under the governance of the Linux Foundation for AI (now LF AI and Data Foundation) in 2020.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f7aac8e5-93a6-4551-b76b-53dae46d786f', $q$What is a feature store and why does it matter?$q$, $q$A feature store centralizes the computation and storage of machine learning input variables so they can be reused consistently across model training and live production inference, avoiding duplicated pipelines and mismatches between training and serving data.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f7aac8e5-93a6-4551-b76b-53dae46d786f', $q$Does Feast support real-time or streaming features?$q$, $q$Yes, Feast supports materializing features from streaming pipelines into its online store for low-latency serving, in addition to scheduled batch materialization from the offline store.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f7aac8e5-93a6-4551-b76b-53dae46d786f', $q$Can Feast be used for LLM and RAG applications?$q$, $q$Yes. Newer versions of Feast support storing and retrieving vector embeddings through integrations with stores like Qdrant, Milvus, and Faiss, enabling retrieval-augmented generation and other large language model workloads alongside traditional ML features.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f7aac8e5-93a6-4551-b76b-53dae46d786f', $q$What are the main alternatives to Feast?$q$, $q$The most commonly compared alternatives are Tecton (a managed commercial feature platform), Hopsworks (self-hosted or managed, popular in regulated industries), AWS SageMaker Feature Store, and Databricks Feature Store, each trading off managed convenience against Feast's open source flexibility.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f7aac8e5-93a6-4551-b76b-53dae46d786f', $q$Real-time fraud and risk scoring$q$, $q$Financial services and fintech teams use Feast to serve up-to-date behavioral and transaction features to fraud and risk models with low latency, while training those same models on point-in-time correct historical data.$q$, $q$Fintech and banking ML engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f7aac8e5-93a6-4551-b76b-53dae46d786f', $q$Recommendation and personalization systems$q$, $q$E-commerce and consumer platforms use Feast to centralize user and item features shared across multiple recommendation and ranking models, reducing duplicated feature engineering across product teams.$q$, $q$E-commerce and consumer technology companies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f7aac8e5-93a6-4551-b76b-53dae46d786f', $q$Retrieval-augmented generation for LLM applications$q$, $q$AI engineering teams use Feast's vector store integrations to manage embeddings and retrieval alongside conventional features, supporting RAG pipelines and other generative AI applications.$q$, $q$AI and machine learning platform teams building generative AI products$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f7aac8e5-93a6-4551-b76b-53dae46d786f', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full source code access under the Apache License 2.0","Self-hosted deployment on infrastructure you control","No feature, user, or usage limits imposed by the software","Community support via GitHub and Slack","Access to the full library of offline, online, and vector store integrations"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f7aac8e5-93a6-4551-b76b-53dae46d786f', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Feast is an open source feature store, a piece of data infrastructure that lets machine learning teams define, compute, store, and serve the input variables ('features') that models rely on, using one consistent definition for both training and live inference. It was created in 2018 by Gojek and Google Cloud and is now governed as an independent project under the LF AI and Data Foundation, part of the Linux Foundation.$q$, $q$The project pairs an offline store, typically a data warehouse such as BigQuery, Snowflake, or Redshift, used for historical feature extraction during model training, with an online store, typically a low-latency key-value database such as Redis or DynamoDB, used to serve the freshest feature values to production models in milliseconds. A central registry tracks feature definitions as versioned metadata, and a Python SDK plus optional REST feature server let engineering teams read, write, and discover features programmatically.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f7aac8e5-93a6-4551-b76b-53dae46d786f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Feast's core technical differentiator is point-in-time correct joins, which automatically align historical feature values to the exact timestamp of each training example, preventing models from accidentally training on future data that would not have been available at prediction time.$q$, $q$Beyond structured, tabular features, Feast has expanded to support vector embeddings and similarity search through integrations with stores like Qdrant, Milvus, and Faiss, making it usable for retrieval-augmented generation (RAG) and other large language model applications, alongside data quality monitoring and observability tooling for inspecting what has actually been served in production.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f7aac8e5-93a6-4551-b76b-53dae46d786f', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Feast itself is completely free. It is released under the Apache License 2.0, meaning the source code can be downloaded, self-hosted, modified, and redistributed without any license fee, subscription, or usage cap imposed by the project.$q$, $q$There is no official managed Feast-as-a-service offering, so adopting teams pay only for the underlying cloud infrastructure they choose to run it on, such as a data warehouse, a Redis or DynamoDB cluster, and compute for materialization jobs, plus the engineering time to operate that infrastructure. Organizations wanting a managed alternative typically look to commercial vendors like Tecton rather than to Feast directly.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f7aac8e5-93a6-4551-b76b-53dae46d786f', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f7aac8e5-93a6-4551-b76b-53dae46d786f', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f7aac8e5-93a6-4551-b76b-53dae46d786f', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f7aac8e5-93a6-4551-b76b-53dae46d786f', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f7aac8e5-93a6-4551-b76b-53dae46d786f', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('94397512-e81a-4da3-8e0a-9e8fa8ba4e79', $q$Real-time flag propagation$q$, $q$Flag and segment changes are pushed to connected SDKs over WebSocket connections, reaching them in under 100 milliseconds according to FeatBit, avoiding the delay inherent in polling-based SDKs.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('94397512-e81a-4da3-8e0a-9e8fa8ba4e79', $q$Progressive rollouts and targeting$q$, $q$Roll a feature out to as little as one percent of traffic, target individual users, or build reusable audience segments based on user attributes for precise, gradual releases.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('94397512-e81a-4da3-8e0a-9e8fa8ba4e79', $q$A/B testing and experimentation$q$, $q$Built-in multivariate flags and experimentation tooling let teams measure the impact of a change against product metrics before rolling it out broadly.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('94397512-e81a-4da3-8e0a-9e8fa8ba4e79', $q$Self-hosting with full data ownership$q$, $q$The full platform can be self-hosted via Docker Compose, Kubernetes/Helm charts, Terraform on AWS, or Azure Container Apps, keeping flag data and evaluation entirely inside a team's own infrastructure.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('94397512-e81a-4da3-8e0a-9e8fa8ba4e79', $q$Broad SDK and OpenFeature support$q$, $q$Official SDKs cover .NET/C#, JavaScript, React, React Native, Node.js, Java, Python, and Go, plus OpenFeature providers for teams standardizing on the vendor-neutral OpenFeature specification.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('94397512-e81a-4da3-8e0a-9e8fa8ba4e79', $q$Governance and audit workflows$q$, $q$Audit logs, scheduled flag changes, and change-approval workflows give teams control and traceability over who changed a flag and when, useful for compliance-sensitive environments.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('94397512-e81a-4da3-8e0a-9e8fa8ba4e79', $q$Relay Proxy for distributed deployments$q$, $q$The FeatBit Agent (Relay Proxy) caches flag data closer to application servers, reducing latency and connection load in multi-region or edge deployments.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('94397512-e81a-4da3-8e0a-9e8fa8ba4e79', $q$AI agent integration via MCP server$q$, $q$A hosted Model Context Protocol server lets AI coding agents create, evaluate, list, and update feature flags through natural-language instructions, aimed at AI-assisted release workflows.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('94397512-e81a-4da3-8e0a-9e8fa8ba4e79', $q$MIT-licensed open-source core with no seat-based, MAU-based, or API-call-based pricing limits, even on paid tiers.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('94397512-e81a-4da3-8e0a-9e8fa8ba4e79', $q$Self-hosting gives teams full control over where feature flag data lives, which appeals to security- and compliance-sensitive organizations.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('94397512-e81a-4da3-8e0a-9e8fa8ba4e79', $q$Sub-100-millisecond WebSocket-based flag propagation avoids the lag of polling-based feature flag SDKs.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('94397512-e81a-4da3-8e0a-9e8fa8ba4e79', $q$Broad SDK coverage plus OpenFeature provider support reduces vendor lock-in risk for teams standardizing on the open specification.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('94397512-e81a-4da3-8e0a-9e8fa8ba4e79', $q$Self-hosting requires operating and maintaining infrastructure (MongoDB, Redis, application services) rather than relying on a fully managed vendor.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('94397512-e81a-4da3-8e0a-9e8fa8ba4e79', $q$The commercial company behind the project has limited publicly documented information about its size, funding, and headquarters, which may concern buyers doing enterprise vendor diligence.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('94397512-e81a-4da3-8e0a-9e8fa8ba4e79', $q$Open-source community size (roughly 1.9 thousand GitHub stars) is smaller than more established open-source alternatives like Unleash, which may mean a smaller pool of community plugins and third-party integrations.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('94397512-e81a-4da3-8e0a-9e8fa8ba4e79', $q$Advanced governance features such as flag approval workflows and audit logs require the paid Enterprise tier rather than being available in the free Foundation tier.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('94397512-e81a-4da3-8e0a-9e8fa8ba4e79', $q$Is FeatBit free to use?$q$, $q$Yes. FeatBit's Foundation tier is the full open-source platform released under the MIT license, and it is free to self-host indefinitely. Paid Enterprise and Enterprise Premium tiers add support, governance, and scaling features on top of the same core platform.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('94397512-e81a-4da3-8e0a-9e8fa8ba4e79', $q$Can FeatBit be self-hosted?$q$, $q$Yes, self-hosting is central to FeatBit's design. It can be deployed via Docker Compose, Kubernetes using Helm charts, Terraform modules for AWS, or Azure Container Apps, giving teams full control over where flag data and evaluation logic run.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('94397512-e81a-4da3-8e0a-9e8fa8ba4e79', $q$What programming languages does FeatBit support?$q$, $q$FeatBit provides official SDKs for .NET/C#, JavaScript, React, React Native, Node.js, Java, Python, and Go, and it also supports OpenFeature providers for teams using the vendor-neutral OpenFeature specification.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('94397512-e81a-4da3-8e0a-9e8fa8ba4e79', $q$How is FeatBit priced compared to LaunchDarkly?$q$, $q$Unlike many commercial feature flag vendors, FeatBit states that it does not charge based on seats, monthly active users, or API calls. Its self-hosted Enterprise tier is a flat annual fee (3,999 dollars per year at time of research), which the company positions as significantly cheaper at scale than seat- or MAU-metered competitors like LaunchDarkly.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('94397512-e81a-4da3-8e0a-9e8fa8ba4e79', $q$Does FeatBit support A/B testing and experimentation?$q$, $q$Yes. FeatBit includes multivariate flags and built-in experimentation tooling that let teams run A/B tests and measure the impact of a rollout against product metrics, in addition to standard percentage-based progressive rollouts.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('94397512-e81a-4da3-8e0a-9e8fa8ba4e79', $q$Does FeatBit integrate with AI coding agents?$q$, $q$Yes. FeatBit publishes a hosted Model Context Protocol (MCP) server that lets AI coding agents such as Claude Code create, evaluate, list, and update feature flags through natural-language instructions, aligning with FeatBit's positioning around AI-native release engineering.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('94397512-e81a-4da3-8e0a-9e8fa8ba4e79', $q$Progressive rollout of new features$q$, $q$Engineering teams wrap a new feature in a flag and gradually increase exposure from a small percentage of users to full availability, watching metrics and error rates at each step before continuing.$q$, $q$Product engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('94397512-e81a-4da3-8e0a-9e8fa8ba4e79', $q$Self-hosted feature management for regulated environments$q$, $q$Organizations with strict data residency or compliance requirements self-host FeatBit inside their own cloud or on-premises infrastructure so feature flag data never leaves their environment.$q$, $q$Security and compliance-focused engineering organizations$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('94397512-e81a-4da3-8e0a-9e8fa8ba4e79', $q$AI-assisted release engineering$q$, $q$Teams building AI-powered features use FeatBit's MCP server so AI coding agents can create and adjust feature flags directly, and use flags to control which AI model, prompt version, or agent skill is active for a given user cohort.$q$, $q$AI product and platform engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('94397512-e81a-4da3-8e0a-9e8fa8ba4e79', $q$Foundation (Open Source)$q$, $q$Free$q$, $q$Perpetual$q$, NULL, $q$["Full-featured open-source platform, self-hosted with complete data ownership","Core feature flag console and REST API","SDKs for .NET, JavaScript, React, React Native, Node.js, Java, Python, and Go, plus OpenFeature providers","Webhooks and real-time WebSocket flag updates","Basic role-based access control","Community support via Discord and GitHub"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('94397512-e81a-4da3-8e0a-9e8fa8ba4e79', $q$Enterprise$q$, $q$$3,999/year$q$, $q$Annual$q$, NULL, $q$["All Foundation features included","Email support and priority assistance","Audit logs","Flag approval workflows","High-availability advisor","Up to 99 auto-sync Relay Proxy agents","Advanced role-based access control available as an add-on (approximately $600/year)"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('94397512-e81a-4da3-8e0a-9e8fa8ba4e79', $q$Enterprise Premium$q$, $q$Custom pricing$q$, $q$Annual (custom)$q$, NULL, $q$["All Enterprise features included","100+ auto-sync Relay Proxy agents","Dedicated engineering support","Custom SLAs","Onboarding and training"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('94397512-e81a-4da3-8e0a-9e8fa8ba4e79', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$FeatBit is an open-source feature flag and experimentation platform that lets engineering teams separate code deployment from feature release. Teams wrap new functionality behind a flag, then use FeatBit's console or API to decide who sees it, when, and at what rollout percentage, without needing a new deployment to change behavior in production.$q$, $q$The project is built primarily in C# on .NET with an Angular-based web console, and it stores data in MongoDB (with documented support for Azure Cosmos DB and PostgreSQL via FerretDB), using Redis for caching and messaging. Most of the codebase is released under the MIT license, and the platform can be run entirely self-hosted via Docker Compose, Kubernetes/Helm, Terraform on AWS, or Azure Container Apps, or consumed as a managed cloud service.$q$, $q$A defining technical trait is real-time flag propagation over WebSocket connections rather than SDK polling, with the company stating that flag changes reach connected SDKs in under 100 milliseconds. This is combined with SDKs for .NET, JavaScript, React, React Native, Node.js, Java, Python, and Go, plus OpenFeature provider support for teams standardizing on the vendor-neutral OpenFeature spec.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('94397512-e81a-4da3-8e0a-9e8fa8ba4e79', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Beyond basic on/off toggles, FeatBit supports progressive rollouts starting at as little as one percent of traffic, individual user targeting, reusable audience segments, multivariate flags for A/B and multivariate experiments, and built-in experimentation tooling for measuring the impact of a release against product metrics.$q$, $q$Governance features include audit logs, scheduled flag changes, and change-approval workflows, alongside integrations with Datadog, New Relic, Grafana, and Slack, and OpenTelemetry support for tracing. A Relay Proxy ('FeatBit Agent') caches flag data closer to application servers for distributed or edge deployments.$q$, $q$FeatBit has more recently added AI-native tooling, including a hosted Model Context Protocol (MCP) server at mcp.featbit.co that lets AI coding agents like Claude Code create, evaluate, list, and update feature flags via natural-language instructions, framed around use cases such as controlling which versions of AI agent skills or tools are active for different user cohorts.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('94397512-e81a-4da3-8e0a-9e8fa8ba4e79', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$FeatBit's self-hosted pricing is structured around feature access and support level rather than usage-based metering: the company states that no self-hosted plan charges based on seats, monthly active users, or API calls.$q$, $q$The free Foundation tier is the full open-source, MIT-licensed platform, self-hosted with complete data ownership, including the core console, REST API, SDKs, webhooks, real-time WebSocket updates, basic role-based access control, and community support.$q$, $q$The Enterprise tier is priced at 3,999 dollars per year and adds email and priority support, audit logs, flag approval workflows, a high-availability advisor, and up to 99 auto-sync Relay Proxy agents, with advanced role-based access control available as a roughly 600-dollar-per-year add-on. An Enterprise Premium tier offers custom pricing for large-scale deployments needing 100-plus auto-sync agents, dedicated engineering support, and custom SLAs. A cloud-hosted (SaaS) option with annual discounts is also available by contacting FeatBit's sales team.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('94397512-e81a-4da3-8e0a-9e8fa8ba4e79', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
