INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('94397512-e81a-4da3-8e0a-9e8fa8ba4e79', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('acaa6370-6b47-4ce4-a037-fe2c52fd137b', $q$Visual Rule Builder$q$, $q$Define conditional logic in natural language to show, hide, or branch form steps based on user responses, without writing code.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('acaa6370-6b47-4ce4-a037-fe2c52fd137b', $q$Custom JavaScript Editor$q$, $q$Full JavaScript access for custom validation, edge-case handling, and data manipulation beyond what visual logic tools support.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('acaa6370-6b47-4ce4-a037-fe2c52fd137b', $q$React and JavaScript SDK$q$, $q$Embed Feathery forms directly into web and mobile applications with minimal code, and set styles or logic programmatically at runtime.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('acaa6370-6b47-4ce4-a037-fe2c52fd137b', $q$White-Labeled, Brand-Controlled Forms$q$, $q$Remove Feathery branding, apply custom CSS and HTML, and serve forms on a custom subdomain or fully custom DNS domain.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('acaa6370-6b47-4ce4-a037-fe2c52fd137b', $q$100+ Native Integrations$q$, $q$Connect to CRMs like Salesforce, payment processors like Stripe, identity providers like Plaid and Alloy, and analytics and project management tools.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('acaa6370-6b47-4ce4-a037-fe2c52fd137b', $q$Native A/B Testing and Analytics$q$, $q$Run experiments directly on live forms and analyze submission and completion data to optimize conversion without third-party tools.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('acaa6370-6b47-4ce4-a037-fe2c52fd137b', $q$Enterprise Security and Compliance$q$, $q$SOC 2 coverage on the free tier, with HIPAA, GDPR, data sovereignty, SSO, role-based access control, and audit logging on paid tiers.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('acaa6370-6b47-4ce4-a037-fe2c52fd137b', $q$AI Document Intelligence and Robin Assistant$q$, $q$Extract structured data from documents and meeting recordings, and use the Robin AI assistant to build and manage workflows through natural language.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('acaa6370-6b47-4ce4-a037-fe2c52fd137b', $q$Extensive customization, from natural-language conditional logic to raw JavaScript and CSS control, well beyond most form builders$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('acaa6370-6b47-4ce4-a037-fe2c52fd137b', $q$Deep native integrations covering CRM, payments, identity verification, and authentication out of the box$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('acaa6370-6b47-4ce4-a037-fe2c52fd137b', $q$Developer-first React and JavaScript SDK makes embedding forms into existing products straightforward$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('acaa6370-6b47-4ce4-a037-fe2c52fd137b', $q$SOC 2 compliance included even on the Free tier, with HIPAA and GDPR options for regulated industries on paid tiers$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('acaa6370-6b47-4ce4-a037-fe2c52fd137b', $q$Steeper learning curve for non-technical users compared to simpler tools like Tally or Typeform$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('acaa6370-6b47-4ce4-a037-fe2c52fd137b', $q$Growth and Business tiers require a custom quote rather than transparent, fixed self-serve pricing$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('acaa6370-6b47-4ce4-a037-fe2c52fd137b', $q$Free plan is capped at 500 monthly submissions and 5 live forms, modest limits for growing teams$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('acaa6370-6b47-4ce4-a037-fe2c52fd137b', $q$Recent product and go-to-market focus has shifted heavily toward financial services and insurance, which may deprioritize general-purpose form use cases$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('acaa6370-6b47-4ce4-a037-fe2c52fd137b', $q$What is Feathery used for?$q$, $q$Feathery is used to build customizable, logic-driven forms and multi-step workflows, ranging from product signup and onboarding flows to, more recently, financial services processes like client onboarding, account opening, and insurance underwriting intake.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('acaa6370-6b47-4ce4-a037-fe2c52fd137b', $q$Does Feathery have a free plan?$q$, $q$Yes. Feathery's Free plan costs 0 dollars per month and includes up to 500 monthly submissions, 5 live forms, 1 seat, and SOC 2 compliance coverage, with community forum support.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('acaa6370-6b47-4ce4-a037-fe2c52fd137b', $q$Can developers embed Feathery forms into their own applications?$q$, $q$Yes. Feathery provides a React and JavaScript SDK that lets developers embed forms directly into web and mobile applications and control styling and logic programmatically at runtime.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('acaa6370-6b47-4ce4-a037-fe2c52fd137b', $q$Is Feathery HIPAA and SOC 2 compliant?$q$, $q$SOC 2 coverage is included starting on the Free plan. HIPAA compliance, GDPR support, and data sovereignty options are available on Feathery's paid Growth and Business tiers.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('acaa6370-6b47-4ce4-a037-fe2c52fd137b', $q$Who are Feathery's main competitors?$q$, $q$Feathery is commonly compared to Typeform, Jotform, Formstack, and Tally in the general form-builder category, and to Form.io among more developer-oriented platforms. It differentiates through deeper conditional logic, a developer SDK, and native A/B testing.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('acaa6370-6b47-4ce4-a037-fe2c52fd137b', $q$How much does Feathery cost beyond the free plan?$q$, $q$Feathery's paid Growth and Business plans are sold on a custom-quote basis rather than a fixed public price, reflecting the company's focus on larger, higher-touch enterprise and financial services accounts.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('acaa6370-6b47-4ce4-a037-fe2c52fd137b', $q$Developer-Embedded Product Onboarding$q$, $q$Product and engineering teams use Feathery's React and JavaScript SDK to build brand-consistent signup, onboarding, and payment forms embedded directly inside their own applications.$q$, $q$Product and engineering teams at SaaS and technology companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('acaa6370-6b47-4ce4-a037-fe2c52fd137b', $q$Financial Services Client Onboarding$q$, $q$Wealth management firms use Feathery to automate client onboarding, account opening, proposal generation, and account maintenance workflows with logic-driven, compliant forms.$q$, $q$RIAs, broker-dealers, and wealth management firms$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('acaa6370-6b47-4ce4-a037-fe2c52fd137b', $q$Insurance Underwriting and Submission Intake$q$, $q$Insurance carriers and brokers use Feathery to automate submission intake, book roll ingestion, policy checks, and proposal generation across personal and commercial lines.$q$, $q$Insurance carriers, managing general agents, and brokers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('acaa6370-6b47-4ce4-a037-fe2c52fd137b', $q$Free$q$, $q$$0$q$, $q$monthly$q$, NULL, $q$["500 monthly submissions","5 live forms","10MB file upload size","1 seat","Unlimited questions, pages, conditions, styles and components","Partial submissions and saved progress","Standard integrations plus Stripe, Salesforce, SMS OTP, Plaid, Alloy and LexisNexis","Firebase and Stytch authentication","SOC 2 coverage","Forum support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('acaa6370-6b47-4ce4-a037-fe2c52fd137b', $q$Growth$q$, $q$Custom pricing$q$, $q$custom$q$, NULL, $q$["Unlimited monthly submissions","Custom number of live forms","Remove Feathery branding","Custom SEO metadata","Custom HTML and CSS","Custom subdomain and custom DNS domain","CAPTCHA","Native A/B testing","Logic and API connectors","Premium integrations","HIPAA, GDPR and data sovereignty options","Priority email and live chat support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('acaa6370-6b47-4ce4-a037-fe2c52fd137b', $q$Business$q$, $q$Custom pricing$q$, $q$custom$q$, NULL, $q$["All Growth features","Role-based access controls","Single sign-on","Audit logs","White label editor","Multiple workspaces","Full compliance suite","Priority support plus custom form-building services"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('acaa6370-6b47-4ce4-a037-fe2c52fd137b', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Feathery is a low-code platform for building forms and multi-step user journeys, originally aimed at developers and product teams who needed more customization and logic depth than typical form builders allow. Users design forms in a visual, drag-and-drop editor, then layer on conditional logic, custom JavaScript, and API-driven data flows for cases that pure no-code tools cannot handle.$q$, $q$Founded in San Francisco in 2021 by Peter Dun and Zack Khan, Feathery launched publicly in July 2022 after a year of working with fintech and healthcare beta customers. The platform embeds via a React and JavaScript SDK, integrates with over 100 third-party tools, and supports white-labeled, fully brand-controlled forms rather than vendor-hosted pages.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('acaa6370-6b47-4ce4-a037-fe2c52fd137b', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Feathery's Rule Builder lets non-engineers define conditional logic in natural language, while a JavaScript editor gives developers full control over edge cases, custom validation, and data manipulation. Forms can read from external APIs and write submitted data directly into a company's internal systems as part of the submission flow.$q$, $q$The platform includes native A/B testing and analytics for optimizing form conversion, identity and fraud checks through Plaid, Alloy, and LexisNexis, authentication via Firebase and Stytch, and native Stripe payments. Higher tiers add custom domains, CAPTCHA, single sign-on, role-based access control, audit logs, and a white-label editor for agencies and enterprises managing many client-facing forms.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('acaa6370-6b47-4ce4-a037-fe2c52fd137b', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Feathery's official pricing page lists three tiers: Free (0 dollars per month, 500 monthly submissions, 5 live forms, 1 seat, SOC 2 coverage, and community support), Growth (custom pricing, unlimited submissions, branding removal, A/B testing, custom domains, HIPAA and GDPR options, priority support), and Business (custom pricing, adding SSO, RBAC, audit logs, white-labeling, and multiple workspaces).$q$, $q$Both paid tiers are sold on a custom-quote basis rather than a fixed self-serve price, reflecting Feathery's shift toward larger, higher-touch enterprise accounts, particularly in insurance and wealth management. Third-party aggregators have historically cited fixed prices in the 49 to 190 dollar per month range for earlier versions of the paid tiers, but the current live pricing page shows custom pricing for both Growth and Business.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('acaa6370-6b47-4ce4-a037-fe2c52fd137b', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
