INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('acaa6370-6b47-4ce4-a037-fe2c52fd137b', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('69ed37d5-2093-4b7b-87b5-2affc6a03505', $q$Public Feedback Boards$q$, $q$Customer-facing boards where users submit feature requests, vote, and comment, with admin tools to organize posts, apply statuses, and merge duplicates.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('69ed37d5-2093-4b7b-87b5-2affc6a03505', $q$Visual Product Roadmap$q$, $q$A public roadmap that displays planned, in-progress, and shipped items in real time, giving customers transparency into what is being built.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('69ed37d5-2093-4b7b-87b5-2affc6a03505', $q$Changelog and Release Announcements$q$, $q$Publish release notes to a branded changelog page, email digests, and an embeddable in-app widget, with segmentation by user attributes.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('69ed37d5-2093-4b7b-87b5-2affc6a03505', $q$AI-Powered Prioritization$q$, $q$AI detects duplicate submissions, surfaces patterns across large volumes of feedback, and supports revenue-based prioritization tied to customer and subscription data.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('69ed37d5-2093-4b7b-87b5-2affc6a03505', $q$Fibi AI Support Agent$q$, $q$An AI agent with full workspace context that resolves customer questions automatically, logs feature requests on a customer's behalf, and runs configurable support workflows.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('69ed37d5-2093-4b7b-87b5-2affc6a03505', $q$Unified Support Inbox$q$, $q$Consolidates conversations from in-app chat, email, Slack, and Discord into a single queue for support teams.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('69ed37d5-2093-4b7b-87b5-2affc6a03505', $q$AI-Native Help Center$q$, $q$A Notion-style documentation editor with AI search that surfaces instant answers, supporting multiple brands and content in 40 or more languages.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('69ed37d5-2093-4b7b-87b5-2affc6a03505', $q$Third-Party Integrations$q$, $q$Connects with Slack, Discord, Intercom, HubSpot, Zendesk, Jira, Linear, GitHub, ClickUp, Azure DevOps, Segment, and Zapier to sync statuses and route conversations.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('69ed37d5-2093-4b7b-87b5-2affc6a03505', $q$Generous free plan and low entry-priced paid tiers compared to legacy enterprise feedback tools$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('69ed37d5-2093-4b7b-87b5-2affc6a03505', $q$Clean, modern interface that reviewers consistently describe as easier to use than older competitors like UserVoice or Productboard$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('69ed37d5-2093-4b7b-87b5-2affc6a03505', $q$Combines feedback, roadmap, changelog, and support inbox in one workspace, reducing the need for separate tools$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('69ed37d5-2093-4b7b-87b5-2affc6a03505', $q$AI-assisted duplicate detection and Fibi support agent are considered strong differentiators in third-party comparisons$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('69ed37d5-2093-4b7b-87b5-2affc6a03505', $q$Some advanced features, such as SLAs, workflow automation, and API and webhook access, are gated behind higher-priced Professional and Enterprise tiers$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('69ed37d5-2093-4b7b-87b5-2affc6a03505', $q$Per-seat pricing can become expensive for larger support and product teams compared to per-tracked-user pricing models used by some competitors$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('69ed37d5-2093-4b7b-87b5-2affc6a03505', $q$Analytics and reporting depth are noted by reviewers as less mature than longer-established competitors like Canny$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('69ed37d5-2093-4b7b-87b5-2affc6a03505', $q$Branding and customization options for public-facing boards are described by some users as somewhat limited$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('69ed37d5-2093-4b7b-87b5-2affc6a03505', $q$What is Featurebase used for?$q$, $q$Featurebase is used to collect and prioritize customer feedback, publish a public product roadmap, announce updates through a changelog, and, in its newer support modules, manage customer conversations through a shared inbox and AI agent.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('69ed37d5-2093-4b7b-87b5-2affc6a03505', $q$Is Featurebase free to use?$q$, $q$Yes, Featurebase offers a permanent Free plan for a single seat with live chat and a unified inbox, though paid plans starting at 29 dollars per seat per month are required for the Fibi AI agent, custom domains, and deeper integrations.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('69ed37d5-2093-4b7b-87b5-2affc6a03505', $q$How is Featurebase different from Canny?$q$, $q$Featurebase bundles a support inbox, live chat, and AI agent alongside its feedback and roadmap tools and bills per seat, while Canny focuses more narrowly on feedback management, bills by tracked user, and offers deeper analytics and a longer-established integration catalog.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('69ed37d5-2093-4b7b-87b5-2affc6a03505', $q$Who founded Featurebase?$q$, $q$Featurebase was founded at the end of 2020 by Robi Rohumaa and Bruno Hiis in Tallinn, Estonia, with Markus Palm later joining as a co-founder focused on go-to-market; the company is bootstrapped and has not raised outside funding.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('69ed37d5-2093-4b7b-87b5-2affc6a03505', $q$What integrations does Featurebase support?$q$, $q$Featurebase integrates with Slack, Discord, Intercom, HubSpot, Zendesk, Jira, Linear, GitHub, ClickUp, Azure DevOps, Segment, and Zapier, among others.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('69ed37d5-2093-4b7b-87b5-2affc6a03505', $q$Does Featurebase have an AI feature?$q$, $q$Yes, Featurebase includes an AI support agent called Fibi that automatically resolves customer questions, logs feature requests on a customer's behalf, and can run configurable support workflows, alongside AI-assisted duplicate detection and prioritization for feedback.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('69ed37d5-2093-4b7b-87b5-2affc6a03505', $q$Startup feedback and roadmap management$q$, $q$Early-stage SaaS teams use the free or Growth plan to collect feature requests, publish a public roadmap, and keep users informed through changelogs without investing in a heavyweight product management suite.$q$, $q$Startup founders and product managers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('69ed37d5-2093-4b7b-87b5-2affc6a03505', $q$AI-assisted customer support$q$, $q$Growing support teams use the unified inbox and Fibi AI agent to resolve routine customer questions automatically while routing feedback captured during support conversations directly into the product feedback board.$q$, $q$Customer support and success teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('69ed37d5-2093-4b7b-87b5-2affc6a03505', $q$Enterprise multi-brand support and feedback$q$, $q$Larger, multi-team organizations use the Enterprise plan's multi-brand workspace, SSO, and custom admin roles to run feedback and support operations across multiple products or customer segments under one governance model.$q$, $q$Enterprise product and support operations teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('69ed37d5-2093-4b7b-87b5-2affc6a03505', $q$Free$q$, $q$$0$q$, $q$Forever free$q$, NULL, $q$["1 seat","Live chat","Unlimited conversations","Unified inbox and ticketing","Mobile app","Assign and snooze conversations","Internal notes"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('69ed37d5-2093-4b7b-87b5-2affc6a03505', $q$Growth$q$, $q$$29/seat/month$q$, $q$Billed yearly$q$, NULL, $q$["Fibi AI agent (AI resolutions billed at approximately $0.49 each)","Email support","AI copilot","AI replies and macros","Custom domains","Basic analytics","Core integrations"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('69ed37d5-2093-4b7b-87b5-2affc6a03505', $q$Professional$q$, $q$$59/seat/month$q$, $q$Billed yearly$q$, NULL, $q$["Slack support","Workflows and automations","SLAs","User segmentation","Multilingual support","API, MCP, and webhooks","20 free Lite seats included"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('69ed37d5-2093-4b7b-87b5-2affc6a03505', $q$Enterprise$q$, $q$$99/seat/month$q$, $q$Billed yearly, requires a sales demo$q$, NULL, $q$["Multi-brand workspace","SSO and identity management","Custom admin roles","Advanced HubSpot integration","Azure DevOps and Active Directory integrations","Custom invoicing","50 free Lite seats included"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('69ed37d5-2093-4b7b-87b5-2affc6a03505', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Featurebase is a customer feedback and product management platform that centers on three connected modules: a public feedback board where users submit and vote on feature requests, a visual roadmap showing what is planned, in progress, and shipped, and a changelog for announcing releases. It is commonly compared to Canny, UserVoice, Productboard, and Frill as a way for SaaS companies to collect and prioritize user input in a transparent, public-facing way.$q$, $q$Founded at the end of 2020 by Robi Rohumaa and Bruno Hiis in Tallinn, Estonia, with Markus Palm later joining to lead go-to-market, Featurebase has grown as a small, bootstrapped, profitable team without external venture funding. What began as a focused feedback and roadmap tool has since expanded into a broader 'modern support and feedback platform' that also includes a shared support inbox, live chat, a help center, and an AI support agent called Fibi, reflecting the founders' aim to build a faster, better-designed alternative to legacy feedback tools.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('69ed37d5-2093-4b7b-87b5-2affc6a03505', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The feedback portal lets customers and internal teams submit ideas, upvote and comment on existing posts, and track status changes, while admins organize submissions into boards, merge duplicates, and prioritize requests using AI-assisted pattern detection and revenue-based scoring that ties feedback to customer and subscription data. The public roadmap and changelog close the loop by showing what is being built and automatically notifying everyone who engaged with a request once it ships.$q$, $q$On the support side, a unified inbox consolidates conversations from in-app chat, email, Slack, and Discord, and the Fibi AI agent uses full context from the workspace, including help center articles, past conversations, feedback posts, and the roadmap, to resolve routine questions automatically, log new feature requests on a customer's behalf, and run configurable workflows such as trial extensions or discounts. Featurebase also integrates with tools including Slack, Discord, Intercom, HubSpot, Zendesk, Jira, Linear, GitHub, ClickUp, Azure DevOps, Segment, and Zapier.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('69ed37d5-2093-4b7b-87b5-2affc6a03505', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Featurebase offers a permanent Free plan for a single seat with live chat, unlimited conversations, and a unified inbox, followed by three paid, per-seat annual tiers: Growth at 29 dollars per seat per month adds the Fibi AI agent, AI copilot, custom domains, and basic analytics; Professional at 59 dollars per seat per month adds Slack support, workflow automation, SLAs, user segmentation, and API, MCP, and webhook access; and Enterprise at 99 dollars per seat per month, available via a sales demo, adds a multi-brand workspace, SSO, custom admin roles, and deeper integrations. AI resolutions on paid plans are billed separately at roughly 0.49 dollars each.$q$, $q$Early-stage companies founded less than two years ago with fewer than six employees can apply for a startup program offering around 86 percent off Featurebase plus a free year of the Fibi AI agent, underscoring the company's continued focus on startups even as its enterprise tier has matured.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('69ed37d5-2093-4b7b-87b5-2affc6a03505', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('69ed37d5-2093-4b7b-87b5-2affc6a03505', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('69ed37d5-2093-4b7b-87b5-2affc6a03505', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('69ed37d5-2093-4b7b-87b5-2affc6a03505', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('69ed37d5-2093-4b7b-87b5-2affc6a03505', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('69ed37d5-2093-4b7b-87b5-2affc6a03505', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e5e577d8-a36b-4321-96a7-960980e7373b', $q$Linked Data Platform REST API$q$, $q$Fedora 4 and later expose a RESTful, LDP-compliant HTTP API for creating, reading, updating, and deleting repository resources using standard web methods.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e5e577d8-a36b-4321-96a7-960980e7373b', $q$RDF and JSON-LD support$q$, $q$Repository resources carry RDF properties natively and can be retrieved in multiple serializations, including JSON-LD, Turtle, RDF/XML, and N-Triples, via content negotiation.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e5e577d8-a36b-4321-96a7-960980e7373b', $q$OCFL-based preservation storage$q$, $q$Since Fedora 6, content is persisted using the Oxford Common File Layout, an open, application-independent, versioned file layout designed for long-term digital preservation.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e5e577d8-a36b-4321-96a7-960980e7373b', $q$Container and binary resource model$q$, $q$Digital objects are modeled as Containers, which hold RDF metadata and can nest child resources, and Binaries, which hold arbitrary file payloads such as images, audio, or documents.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e5e577d8-a36b-4321-96a7-960980e7373b', $q$WebAC authorization$q$, $q$Fine-grained, resource-level access control is implemented through a WebAC authorization module, with earlier XACML and RBACL modules also available in prior versions.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e5e577d8-a36b-4321-96a7-960980e7373b', $q$Migration Toolkit$q$, $q$A community-built Migration Toolkit, released in 2023, helps institutions move existing repository content between Fedora 3, 4, and 6 as they upgrade.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e5e577d8-a36b-4321-96a7-960980e7373b', $q$Front-end ecosystem integrations$q$, $q$Fedora serves as the backend repository layer for open-source front ends including Islandora (Drupal-based) and Samvera's Hyrax and Avalon (Ruby on Rails-based).$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e5e577d8-a36b-4321-96a7-960980e7373b', $q$Event and workflow integration via Camel$q$, $q$Fedora Commons Camel components and integrations allow repository events to trigger external workflows, indexing pipelines, and system-to-system messaging.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e5e577d8-a36b-4321-96a7-960980e7373b', $q$Completely free and open source under the permissive Apache License 2.0, with no licensing costs regardless of collection size.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e5e577d8-a36b-4321-96a7-960980e7373b', $q$Strong alignment with Linked Data and RDF standards, giving institutions flexible, semantically rich, standards-based metadata rather than a proprietary schema.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e5e577d8-a36b-4321-96a7-960980e7373b', $q$Purpose-built preservation storage via OCFL keeps digital content recoverable and interpretable independent of the Fedora software itself, reducing long-term lock-in risk.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e5e577d8-a36b-4321-96a7-960980e7373b', $q$Backed by an established nonprofit governance structure (Lyrasis) and an active community with documented migration tooling, mailing lists, and recurring Fedora Camps.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e5e577d8-a36b-4321-96a7-960980e7373b', $q$Fedora is repository infrastructure rather than a ready-to-use application, so institutions must build or adopt a separate front end such as Islandora or Hyrax to deliver a public interface.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e5e577d8-a36b-4321-96a7-960980e7373b', $q$Deploying and operating Fedora requires meaningful in-house technical capacity (Java, Linked Data, and systems administration expertise), which has limited adoption mostly to larger, well-resourced institutions.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e5e577d8-a36b-4321-96a7-960980e7373b', $q$Major version transitions, such as Fedora 3 to 4 and 4 to 6, have historically required dedicated content migration effort due to underlying architectural changes.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e5e577d8-a36b-4321-96a7-960980e7373b', $q$As self-hosted open-source software, there is no vendor support contract by default; institutions rely on community resources or their own staff for troubleshooting.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e5e577d8-a36b-4321-96a7-960980e7373b', $q$What is Fedora Repository used for?$q$, $q$Fedora is used by libraries, archives, museums, and universities to build institutional repositories and digital libraries for managing, preserving, and providing access to digital collections, including historical, cultural, and scientific materials.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e5e577d8-a36b-4321-96a7-960980e7373b', $q$Is Fedora Repository free?$q$, $q$Yes. Fedora is free and open-source software released under the Apache License 2.0. Institutions can download, self-host, and modify it at no licensing cost, though they still need their own infrastructure and staff to run it.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e5e577d8-a36b-4321-96a7-960980e7373b', $q$Is Fedora the same as Fedora Linux?$q$, $q$No. Fedora Repository (this project) is an institutional digital repository system that originated at Cornell University in 1997, unrelated to Fedora Linux, Red Hat's operating system distribution. The two share a name due to a historical trademark dispute resolved through a coexistence agreement that lets each project use the name in its own domain.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e5e577d8-a36b-4321-96a7-960980e7373b', $q$What is the difference between Fedora 3 and later versions like Fedora 4, 5, and 6?$q$, $q$Fedora 3.x used a datastream-based object model with RDF stored as a separate attached datastream. Fedora 4 was a ground-up rewrite aligning the repository with the W3C Linked Data Platform, storing RDF directly on resources modeled as Containers and Binaries. Fedora 6 further replaced the underlying storage engine with one based on the Oxford Common File Layout for improved long-term preservation.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e5e577d8-a36b-4321-96a7-960980e7373b', $q$Does Fedora provide a public-facing website or search interface out of the box?$q$, $q$No. Fedora is a repository backend exposed through APIs. Institutions typically pair it with a front-end application such as Islandora (Drupal-based) or Samvera's Hyrax (Ruby on Rails-based) to provide discovery, search, and management interfaces.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e5e577d8-a36b-4321-96a7-960980e7373b', $q$Who maintains and governs the Fedora project today?$q$, $q$Fedora's organizational home is Lyrasis, a nonprofit library and cultural heritage consortium. A community Governance Group, formed in 2022 from the merger of the project's former Leadership and Steering groups, sets strategic direction, supported by the broader open-source contributor and member community.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e5e577d8-a36b-4321-96a7-960980e7373b', $q$Institutional and research repositories$q$, $q$Universities and research institutions use Fedora as the backend for institutional repositories storing theses, research data, publications, and scholarly output alongside descriptive and preservation metadata.$q$, $q$University libraries and research institutions$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e5e577d8-a36b-4321-96a7-960980e7373b', $q$Digital preservation of cultural heritage collections$q$, $q$Archives and museums use Fedora, often via Fedora 6's OCFL-based storage, to preserve digitized historical materials, manuscripts, photographs, and audiovisual collections with long-term, format-independent storage guarantees.$q$, $q$Archives and museums$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e5e577d8-a36b-4321-96a7-960980e7373b', $q$Large-scale digital library platforms$q$, $q$Institutions build full-featured digital library applications on top of Fedora using front ends like Islandora or Samvera's Hyrax to manage and expose very large and complex digital collections to the public.$q$, $q$Digital library and repository development teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e5e577d8-a36b-4321-96a7-960980e7373b', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full source code under the Apache License 2.0","Self-hosted deployment on your own infrastructure","Linked Data Platform REST API and RDF support","OCFL-based preservation storage (Fedora 6+)","Community mailing lists, Slack, and documentation","Optional Lyrasis Fedora Membership for governance participation and funding"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e5e577d8-a36b-4321-96a7-960980e7373b', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Fedora (Flexible Extensible Digital Object Repository Architecture) is a free, open-source repository system for managing and preserving digital content at scale. It is not a commercial product from a company but a community-developed platform stewarded by Lyrasis, a nonprofit organization serving libraries, archives, and museums.$q$, $q$Rather than being an end-user application, Fedora is a repository engine: institutions typically pair it with a front-end system such as Islandora or Samvera/Hyrax to provide search, discovery, and content management interfaces for staff and the public.$q$, $q$Fedora traces its lineage to a 1997 Cornell University research project and has gone through several major architectural generations, most notably the Fedora 3.x object/datastream model and the Fedora 4 through 7 generation, which rebuilt the system around Linked Data Platform (LDP) and RDF standards, and later around the Oxford Common File Layout (OCFL) for preservation-grade storage.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e5e577d8-a36b-4321-96a7-960980e7373b', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Fedora exposes a RESTful HTTP API that is compliant with the W3C Linked Data Platform specification, allowing clients to create, read, update, and delete repository resources using standard web protocols and to negotiate RDF representations such as JSON-LD, Turtle, RDF/XML, and N-Triples.$q$, $q$Its persistence layer, since Fedora 6, is built on the Oxford Common File Layout, an open, application-independent specification for versioned digital object storage that keeps content recoverable and interpretable even without the Fedora software itself.$q$, $q$Access control is handled through a WebAC-based authorization module, letting institutions define fine-grained, resource-level permissions consistent with Linked Data access-control conventions.$q$, $q$Because it is designed as modular infrastructure, Fedora integrates with established open-source front ends, including the Drupal-based Islandora platform and the Ruby on Rails-based Samvera/Hyrax ecosystem, rather than dictating a single user interface.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e5e577d8-a36b-4321-96a7-960980e7373b', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Fedora is entirely free and open source under the Apache License 2.0. There are no license fees, seat charges, or paid tiers for the software itself.$q$, $q$Institutions bear their own infrastructure and staffing costs to self-host, configure, and maintain a Fedora-based repository, and many also choose to become Lyrasis Fedora Members, a voluntary program whose financial or in-kind contributions fund shared community development, documentation, and governance rather than purchasing product access.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e5e577d8-a36b-4321-96a7-960980e7373b', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e5e577d8-a36b-4321-96a7-960980e7373b', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e5e577d8-a36b-4321-96a7-960980e7373b', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e5e577d8-a36b-4321-96a7-960980e7373b', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0e6192b5-0793-49cb-96c6-12757f88b772', $q$AI content generation$q$, $q$Generates on-brand captions and full post drafts from a prompt or idea, including an AI hashtag generator and a 'Vibe Marketing' agent that turns loose ideas into ready-to-schedule posts.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0e6192b5-0793-49cb-96c6-12757f88b772', $q$AI image generation$q$, $q$Creates post visuals using third-party image models, including Flux Pro and Nano Banana 2, directly inside the content creation workflow.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0e6192b5-0793-49cb-96c6-12757f88b772', $q$Smart scheduling with posting plans$q$, $q$Automates recurring publishing cadences and best-time recommendations, and reformats a single draft into platform-specific versions for each connected network.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0e6192b5-0793-49cb-96c6-12757f88b772', $q$Content recycling (evergreen posts)$q$, $q$Automatically identifies historically high-performing posts and resurfaces or reschedules them, reducing manual effort to keep evergreen content circulating.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0e6192b5-0793-49cb-96c6-12757f88b772', $q$Multi-platform publishing$q$, $q$Publishes to Facebook, Instagram, X, LinkedIn, TikTok, YouTube, Pinterest, Google Business Profile, Threads, and Discord from a single workspace.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0e6192b5-0793-49cb-96c6-12757f88b772', $q$Approval workflows and collaboration$q$, $q$Lets teams and clients review, comment on, and approve drafts before they go live, supported by shared workspaces for agencies managing multiple brands.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0e6192b5-0793-49cb-96c6-12757f88b772', $q$Unified social inbox$q$, $q$Centralizes comments and messages from connected platforms so teams can reply without switching between each network's native app.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0e6192b5-0793-49cb-96c6-12757f88b772', $q$Performance prediction and analytics$q$, $q$Estimates how a draft is likely to perform before publishing and tracks post-level engagement and performance analytics after it goes live.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0e6192b5-0793-49cb-96c6-12757f88b772', $q$Clean, easy-to-use interface that reviewers frequently praise for day-to-day scheduling.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0e6192b5-0793-49cb-96c6-12757f88b772', $q$Content recycling for evergreen posts is a standout differentiator versus many competitors, including Hootsuite.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0e6192b5-0793-49cb-96c6-12757f88b772', $q$Approval workflows and a unified social inbox are well-suited to agencies coordinating with clients.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0e6192b5-0793-49cb-96c6-12757f88b772', $q$Meaningfully cheaper entry pricing than enterprise tools like Hootsuite while still including AI content generation.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0e6192b5-0793-49cb-96c6-12757f88b772', $q$Instagram publishing reliability issues are a recurring complaint, with some users reporting scheduled posts fail silently or throw unclear errors.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0e6192b5-0793-49cb-96c6-12757f88b772', $q$AI-generated copy can feel generic out of the box and typically needs editing to match a brand's voice.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0e6192b5-0793-49cb-96c6-12757f88b772', $q$No native iOS or Android app as of mid-2026; only a mobile-optimized browser experience is available.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0e6192b5-0793-49cb-96c6-12757f88b772', $q$No permanently free plan, only a 7-day trial, and some users consider pricing high relative to competitors at comparable tiers.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0e6192b5-0793-49cb-96c6-12757f88b772', $q$What is FeedHive used for?$q$, $q$FeedHive is used to plan, generate, schedule, and publish social media content across multiple platforms, and to automatically recycle high-performing evergreen posts, all from a single dashboard.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0e6192b5-0793-49cb-96c6-12757f88b772', $q$Which social platforms does FeedHive support?$q$, $q$FeedHive supports Facebook, Instagram, X (Twitter), LinkedIn, TikTok, YouTube, Pinterest, Google Business Profile, Threads, and Discord, plus integrations with Zapier and Make.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0e6192b5-0793-49cb-96c6-12757f88b772', $q$Does FeedHive have a free plan?$q$, $q$No, FeedHive does not offer a permanently free plan. It offers a 7-day free trial that does not require a credit card, after which a paid subscription is required.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0e6192b5-0793-49cb-96c6-12757f88b772', $q$How much does FeedHive cost?$q$, $q$FeedHive's paid plans start at around $19 per month for the Creator tier and scale up through Brand (around $29/month), Business (around $99/month), and Agency (around $299/month), with annual billing available at a discount.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0e6192b5-0793-49cb-96c6-12757f88b772', $q$Does FeedHive have a mobile app?$q$, $q$As of mid-2026, FeedHive does not offer a native iOS or Android app. It provides a mobile-optimized browser experience for viewing calendars and approving posts, though creating content is more limited on mobile than on desktop.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0e6192b5-0793-49cb-96c6-12757f88b772', $q$How does FeedHive compare to Buffer, Hootsuite, Later, and SocialBee?$q$, $q$FeedHive is generally positioned as cheaper than Hootsuite while adding AI content generation and content recycling that Hootsuite lacks. Compared with Buffer, Later, and SocialBee, FeedHive is often seen as strongest for AI-assisted content and evergreen recycling, while Buffer and Later offer broader platform support and Buffer offers a free tier that FeedHive does not.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0e6192b5-0793-49cb-96c6-12757f88b772', $q$Solo creator scheduling across core platforms$q$, $q$An individual creator connects a handful of social accounts, drafts posts with AI assistance, and schedules them in advance using FeedHive's Creator plan.$q$, $q$Independent creators and solopreneurs$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0e6192b5-0793-49cb-96c6-12757f88b772', $q$Brand team managing approvals across channels$q$, $q$A small marketing team uses FeedHive's approval workflows and shared workspace to let a manager or client sign off on drafts before they publish across several connected accounts.$q$, $q$Small business and brand marketing teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0e6192b5-0793-49cb-96c6-12757f88b772', $q$Agency managing many client accounts under one roof$q$, $q$A social media agency uses FeedHive's Business or Agency plan to manage dozens or hundreds of client social accounts across separate workspaces, with white-label branding and priority support on the top tier.$q$, $q$Social media agencies and consultants$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0e6192b5-0793-49cb-96c6-12757f88b772', $q$Creator$q$, $q$$19/month$q$, $q$Monthly (annual billing available at a discount)$q$, NULL, $q$["4 social accounts","1 workspace","AI content credits included monthly","Automation runs included monthly","Advance scheduling window of about 2 weeks","Capped scheduled posts, drafts, and templates"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0e6192b5-0793-49cb-96c6-12757f88b772', $q$Brand$q$, $q$$29/month$q$, $q$Monthly (annual billing available at a discount)$q$, NULL, $q$["10 social accounts","5 workspaces","Larger AI credit and automation allowance than Creator","Longer advance scheduling window","Approval workflows","AI hashtag generation","Performance prediction"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0e6192b5-0793-49cb-96c6-12757f88b772', $q$Business$q$, $q$$99/month$q$, $q$Monthly (annual billing available at a discount)$q$, NULL, $q$["Around 100 social accounts","50 workspaces","Substantially larger AI credit pool","Unlimited scheduled posts","Unlimited posting plans","Unlimited templates"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0e6192b5-0793-49cb-96c6-12757f88b772', $q$Agency$q$, $q$$299/month$q$, $q$Monthly (annual billing available at a discount)$q$, NULL, $q$["Around 500 social accounts","100 workspaces","Largest AI credit and automation allowance","White-label option","Priority support","Unlimited scheduling and posts"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0e6192b5-0793-49cb-96c6-12757f88b772', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$FeedHive is a cloud-based, AI-powered social media management platform that lets creators, brands, and agencies plan, generate, schedule, and publish content across major social networks from one dashboard. Its core pitch centers on four capabilities: AI content creation, automated scheduling with configurable posting plans, automatic recycling of high-performing evergreen posts, and multi-platform publishing that adapts a single draft into formats suited to each connected channel.$q$, $q$The platform was founded by Simon Hoiberg, who began development in 2020 and publicly launched FeedHive in early 2021 from Zurich, Switzerland, where the company remains headquartered. FeedHive has grown as a bootstrapped, founder-led business without disclosed outside venture funding and currently operates with a small team, reportedly in the 2 to 10 employee range.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0e6192b5-0793-49cb-96c6-12757f88b772', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$FeedHive supports publishing to Facebook, Instagram, X, LinkedIn, TikTok, YouTube, Pinterest, Google Business Profile, Threads, and Discord, with additional workflow integrations through Zapier and Make. Its scheduling engine uses posting plans and conditions to automate recurring publishing cadences and reformat content per platform, while its content recycling engine automatically resurfaces posts that historically performed well, functioning as an evergreen-content system that reduces manual re-promotion work.$q$, $q$AI tooling includes caption and post generation, an AI hashtag generator, performance prediction that estimates how a draft is likely to perform before publishing, AI image generation using models such as Flux Pro and Nano Banana 2, and a 'Vibe Marketing' agent that converts a loose idea into a ready-to-schedule post. FeedHive has also added integrations aimed at developers and AI agents, including connections to Claude Code and OpenClaw, positioning it for programmatic and agentic marketing workflows beyond its own web interface.$q$, $q$For teams, FeedHive provides shared workspaces, content approval flows for client or manager sign-off, comment threads on individual drafts, and a unified social inbox for replying to comments and messages across connected platforms without leaving the app. Rounding out the toolset are a visual content calendar, a reusable template library, custom labels for organizing campaigns or clients, and post-performance analytics.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0e6192b5-0793-49cb-96c6-12757f88b772', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$FeedHive is a paid subscription product with no permanently free plan, though it offers a 7-day free trial that does not require a credit card. Pricing is structured across four tiers -- Creator, Brand, Business, and Agency -- that scale primarily by the number of connected social accounts, workspaces, monthly AI credits, and automation runs.$q$, $q$The Creator plan starts around $19 per month billed monthly (with a lower effective rate available on annual billing) and covers four social accounts and one workspace. The Brand plan, around $29 per month, expands to ten accounts and five workspaces and adds approval workflows, AI hashtag generation, and performance prediction. The Business plan, marketed as FeedHive's most popular tier, runs around $99 per month and scales to roughly 100 accounts and 50 workspaces with unlimited scheduled posts, posting plans, and templates. The top-tier Agency plan, around $299 per month, supports roughly 500 accounts and 100 workspaces and adds white-label branding and priority support for agencies managing many client accounts.$q$]::text[], 2);
